import type { Quiz } from "../quiz-types.js";

export const week3Quizzes: Quiz[] = [
  {
    id: "day6", day: "Day 6", title: "The Competitive Landscape", week: "Week 3",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "A prospect says: 'We already use Google Analytics and it works fine for us.' What's the most accurate competitive weakness of GA4 to anchor your Challenger reframe?", options: ["Google Analytics is too expensive for most mid-market companies", "GA4 can't track mobile apps — it's web-only, which limits its usefulness for product teams", "GA4 is a walled garden with limited ability to do deeper analytics without SQL, GDPR and HIPAA compliance concerns, and a difficult UA-to-GA4 migration that left many teams with degraded data quality", "GA4 doesn't integrate with Salesforce, which makes it useless for revenue-focused analytics"], correct: 2, explanation: "GA4's key weaknesses from the competitive deck are: walled garden (data doesn't flow freely to other tools), can't do deeper behavioral analytics without SQL (limiting self-service), GDPR and HIPAA compliance issues, and the UA-to-GA4 transition left many teams with unreliable data. The Challenger reframe: 'You said it works fine — can I ask, when was the last time a PM answered a behavioral question without needing an analyst to write SQL?' That surfaces the limitation without attacking GA directly.", resource: { label: "Competitive Landscape Deck — T1 Competitors: Google Analytics Weaknesses", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "You're competing against Mixpanel. Your champion tells you: 'Our data team prefers Mixpanel — they say it's best-in-breed for analytics.' How do you respond without badmouthing the competitor?", options: ["Agree and pivot to Amplitude's CDP capabilities — if they want pure analytics, you've already lost that battle", "Mixpanel is a strong point solution for analytics-only buyers, but it's less intuitive for non-technical users and doesn't give marketing and growth teams the self-service access they need. The question is: does your data team want to be the bottleneck for every behavioral question, or should product and marketing be able to answer their own questions?", "Tell them Amplitude has higher G2 ratings and is the market leader — that should address the data team's concern", "Ask to schedule a joint demo with the data team and their VP of Product — getting all stakeholders in the room will reveal Mixpanel's limitations naturally"], correct: 1, explanation: "This is a textbook Trap-Setting move. Mixpanel's weakness is that it's a point solution — less intuitive, less self-service for non-technical personas, and limited governance. The right frame isn't 'Mixpanel is bad' — it's 'who has to service every data request at your company today?' If the answer is the data team, that's the pain. Amplitude's cross-functional data access is the differentiator you're anchoring to. The data team likes Mixpanel because it keeps them central — which is exactly the problem.", resource: { label: "Competitive Landscape Deck — T1 Competitors: Mixpanel", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 3, type: "match", lo: "LO1", text: "Match each Tier 1 competitor to their most accurate competitive profile.", pairs: [{ term: "Google Analytics (GA4)", match: "First tool most customers start on, widely adopted, but walled garden, GDPR/HIPAA issues, can't do deeper analytics without SQL" }, { term: "Mixpanel", match: "'Best-in-breed' point solution that works on analytics-only buyers, but less intuitive and limited governance" }, { term: "Adobe Analytics", match: "Default enterprise analytics, strong marketing brand, but expensive, hard to use, and a walled garden" }, { term: "In-House Solutions", match: "Perceived cost and customizability appeal, but expensive engineer opportunity cost and worst-in-breed point solution with no self-serve" }], correct: 0, explanation: "Knowing the specific strength AND weakness of each competitor is what makes you credible. Prospects have been pitched by all of these vendors. If you say something inaccurate about a competitor, you lose trust instantly. Know each competitor's actual positioning so you can acknowledge their legitimate strengths while exposing the real limitations — that's what Challenger trap-setting requires.", resource: { label: "Competitive Landscape Deck — T1 Competitors Overview", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 4, type: "mc", lo: "LO2", text: "An AE is in a deal where the prospect is also evaluating Statsig. The AE says: 'Statsig is just an experimentation tool — they can't compete with our analytics.' What's wrong with this response?", options: ["Nothing — Statsig is primarily an A/B testing tool and the AE is accurately positioning Amplitude's broader platform", "The AE is underestimating Statsig. Statsig has an advanced experimentation suite and is known for willingness to aggressively undercut on pricing. Dismissing them as 'just experimentation' signals to the prospect that the AE hasn't done their homework — and it leaves the door open for Statsig to win on price.", "The AE should never mention a competitor by name — all competitor references should go through the PMM team", "The AE is correct on capabilities but should add that Statsig is very behind on session replay and analytics, which matters if the prospect cares about the full platform"], correct: 1, explanation: "Statsig's competitive profile per the deck: advanced experimentation suite AND a willingness to undercut pricing aggressively. They are also 'very behind on analytics and replay' — but that weakness doesn't matter if the prospect is analytics-only and primarily cares about experimentation. Dismissing Statsig without understanding the deal shape is lazy. The right approach: understand which capabilities the prospect prioritizes, then position Amplitude's integrated experiment-plus-analytics story versus Statsig's point solution approach.", resource: { label: "Competitive Landscape Deck — The Other Players (T2: Statsig)", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 5, type: "mc", lo: "LO3", text: "A VP of Engineering says: 'We're going to build our own analytics platform internally. It'll be fully customized for our needs and we already have the engineers for it.' Applying Challenger methodology, what's the most effective response?", options: ["Agree that customization is valuable and offer a co-build partnership where Amplitude provides the data layer and they build the UI", "Ask how long the build will take and what the timeline to first insight is — if it's more than 6 months, that's your opening", "Teach: surface the real cost of in-house. 'Customizable' is in-house's strength — but the weakness is engineer opportunity cost, zero self-service for non-technical teams, and no integrations. Ask: what's the cost of every feature request, every dashboard change, every data model update going through your engineering backlog?", "Send a case study of a company that tried to build in-house and failed — let the customer story make the case"], correct: 2, explanation: "In-house solutions look free but aren't. The competitive deck captures this perfectly: the real weakness of in-house is the ongoing engineering opportunity cost and the 'worst-in-breed' outcome — a fragile, custom-built point solution with no self-serve and no integrations. The Challenger move is to Teach the VP of Engineering what they haven't considered: every PM question, every growth analyst request, every executive dashboard — those all become engineering tickets. That's not a product analytics platform. That's a bottleneck.", resource: { label: "Competitive Landscape Deck — T1 Competitors: In-House Solutions", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 6, type: "tf", lo: "LO1", text: "True or False: Pendo is a Tier 1 competitor in the same category as Google Analytics, Mixpanel, and Adobe.", options: ["True", "False"], correct: 1, explanation: "Per the competitive deck, Pendo is a Tier 2 competitor. Its strengths are B2B mid-market presence and being a leader in user guides. Its weaknesses are very limited product analytics and guides that aren't personalized. Pendo shows up most often in B2B SaaS deals where in-app guidance is a priority. Treating Pendo like a Tier 1 analytics competitor misrepresents where it actually competes — and signals to the prospect that you don't know the landscape.", resource: { label: "Competitive Landscape Deck — The Other Players (T2: Pendo)", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 7, type: "mc", lo: "LO3", text: "The three core reasons teams choose Amplitude over competitors are: Breadth & Depth of Insights, Cross-Functional Data Access, and Built for Speed & Action. You're in a competitive deal against Adobe Analytics at an enterprise company. Which reason is most relevant to lead with and why?", options: ["Built for Speed & Action — Adobe is known for being slow and complex, so speed is the most obvious differentiator", "Breadth & Depth of Insights — Adobe has many blades so leading with breadth signals Amplitude can match their platform story", "Cross-Functional Data Access — Adobe is a walled garden that's hard to use, limiting access to technical teams only. Amplitude's no-SQL, no-code self-service means product, marketing, and growth teams can all answer their own questions without going through analysts. That's a business outcome, not a feature.", "All three equally — in a competitive enterprise deal you need to use every differentiator available"], correct: 2, explanation: "Adobe's core weaknesses are: expensive, hard to use, and walled garden. The hardest to use = limited to technical users. In an enterprise, that means the data team is a bottleneck for every insight request. Cross-Functional Data Access directly counters this: 'Anyone with domain knowledge can easily answer their questions without going through a data analyst.' That's a business outcome the VP of Product and CMO can feel — not just a feature checklist. Leading with the most relevant differentiator for the specific competitor is Challenger selling, not feature dumping.", resource: { label: "Competitive Landscape Deck — Why Teams Choose Amplitude (3 Core Reasons)", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "The Challenger concept of influencing a prospect's required capabilities through the benefits of your differentiators — asking questions that make your strengths seem essential — is called ________ questioning.", correct: ["trap-setting", "trap setting", "Trap-Setting", "Trap Setting"], placeholder: "type of questioning...", explanation: "Trap-Setting Questions are designed to influence the prospect's Required Capabilities by surfacing the benefits of your differentiators as needs they didn't know they had. Example: 'When your marketing team needs to understand which campaign drove users who actually retained for 90 days — how long does it take to get that answer today?' You're not saying GA can't do this. You're letting them realize it for themselves. The competitive deck calls this out explicitly: you build trust through thoughtful research and great questions, not by badmouthing competitors.", resource: { label: "Competitive Landscape Deck — Credibility: Trap-Setting Questions", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "You're preparing for a competitive deal and want to find the most current battlecard for Heap. Where do you go?", options: ["Glean — search for 'Heap battlecard' and it will surface the most recent version from any internal source", "The Competitive Highspot page — it's the single source of truth for all competitive content including battlecards, talk tracks, win/loss analysis, and positioning resources", "The #competitive Slack channel — that's where the PMM team posts real-time updates and tactical guidance", "Ask your manager — they'll have the most current competitive intel from deals they've seen in the field"], correct: 1, explanation: "The Competitive Highspot page is the authoritative one-stop shop for all competitive content: battlecards, positioning resources, win/loss analysis, and talk tracks. The #competitive Slack channel is where updates and discussion happen — it's complementary, not a replacement. Your action items from the competitive session: bookmark Highspot Competitive, shadow a competitive deal, and practice your 1-minute 'Why Amplitude vs. [competitor]' for each Tier 1 competitor.", resource: { label: "Competitive Landscape Deck — Resources (Competitive Highspot)", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
      { id: 10, type: "mc", lo: "LO3", text: "Heap is a Tier 2 competitor. An AE dismisses it: 'Heap just does auto-capture — they're not a real threat.' Their prospect is evaluating Heap specifically for its 'zero instrumentation' pitch. What's the risk in this AE's position?", options: ["None — auto-capture is a well-documented weakness of Heap and the AE is correct to dismiss it", "The AE is right about the weakness but wrong to dismiss it. Auto-capture is specifically Heap's marketing strength — prospects who haven't yet instrumented Amplitude may find 'zero setup' compelling. The AE should acknowledge the appeal of auto-capture, then Teach why retroactive data without intentional taxonomy leads to data quality problems and limited analytics depth. Dismissing a competitor's strength without addressing why the prospect finds it appealing is lazy competitive selling.", "The AE should not be discussing Heap's capabilities — all competitive positioning should go through the PMM team before a deal", "The AE is correct — Heap's limited analytics and non-native platform are enough to win any deal where analytics depth matters"], correct: 1, explanation: "Heap's strength per the competitive deck: high SMB awareness, easy pricing, strong web presence. Auto-capture is the core appeal — no instrumentation required. That IS compelling for a prospect who hasn't built an analytics stack yet. Dismissing it without addressing the appeal means the prospect may feel you don't understand their situation. The right Trap-Setting approach: 'Auto-capture is fast to start — but when you need to understand a specific behavioral sequence or slice by a custom attribute, what happens then?' That surfaces the taxonomy and analytics depth limitation without attacking Heap directly.", resource: { label: "Competitive Landscape Deck — The Other Players (T2: Heap)", url: "https://docs.google.com/presentation/d/1ha9NRQs2GiT49ASGf7SiFKYTUcGIbgiveQ2HGhj0q00/edit" } },
    ],
  },
  {
    id: "day7", day: "Day 7", title: "Account Planning Best Practices", week: "Week 3",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "Account planning is now a requirement at Amplitude — but not for every account. Which accounts require a plan?", options: ["All accounts with ARR over $100K", "Top 3 Customers and Top 3 Prospects per Pod, aligned with FLM", "All Enterprise and Emerging Enterprise accounts", "Any account with an active renewal within 180 days"], correct: 1, explanation: "Account plans are required for your Top 3 Customers and Top 3 Prospects — aligned with your FLM and Pod. This focus ensures the planning effort goes toward accounts with the highest impact potential, not spread thin across an entire territory. FLMs conduct monthly reviews (one per Pod per month). If you're unsure which accounts to prioritize, that alignment conversation with your FLM and Pod is the first step.", resource: { label: "Account Planning Best Practices Deck — Takeaways (Top 3 Customers + Top 3 Prospects)", url: "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "Where do Account Plans live and how do you access them?", options: ["In a shared Google Drive folder — each AE maintains their own account plan documents", "In Highspot — account plans are stored alongside account-specific content for easy reference during calls", "In Salesforce — go to the Account record and click 'Open Account Plan' in the top right corner", "In Momentum — the AI-generated deal summaries serve as the account plan for each active opportunity"], correct: 2, explanation: "Account Plans live in Salesforce. Access them by going to the Account record and clicking 'Open Account Plan' in the top right corner. This integration means your plan is connected to your CRM data — deal history, contact relationships, and activity logs — rather than sitting in a disconnected document. Questions or issues with the Account Planning tool? Post in #help-salesops or reach out to Christian Newth or Simon Levison.", resource: { label: "Account Planning Best Practices Deck — Account Plans Live in SFDC", url: "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "An AE owns their account plan and fills it out solo before the monthly review. Their CSM is responsible for reviewing it and adding input afterward. What's wrong with this approach?", options: ["Nothing — the AE owns the commercial relationship and should lead the account plan", "The AE shouldn't be writing account plans at all — that's the CSM's responsibility for existing customers", "Account plans are a joint Pod responsibility with shared ownership between AE and CSM — they should be built together, not serially. The CSM contributes customer priorities/OKRs, growth opportunities, key relationships, business impact, risks, and pain points alongside the AE. Building it solo produces an incomplete plan.", "The AE should loop in the SE and VC before the CSM — technical whitespace is the most important input"], correct: 2, explanation: "The account planning deck is explicit: AE + CSM are accountable but it's a joint Pod responsibility. Per the contributor table, both AE and CSM lead on Customer/Prospect Priorities, Growth Opportunities, Key People, Business Impact, Internal Risks, and Pain Points. The SE/CSA leads on Tech Stack. Everyone contributes to Other Intel. A solo account plan from the AE is incomplete — and a plan that surprises the CSM at the monthly review is a plan that won't be executed well.", resource: { label: "Account Planning Best Practices Deck — Account Plan Contributors (Customers)", url: "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit" } },
      { id: 4, type: "match", lo: "LO1", text: "Match each Account Plan component to who primarily leads it.", pairs: [{ term: "Customer/Prospect Priorities & OKRs", match: "AE / CSM (lead) with SE / CSA contributing" }, { term: "Tech Stack", match: "SE / CSM (lead) with CSA contributing" }, { term: "Business Impact (ROI)", match: "AE / CSM (lead) with VC / SE / CSA contributing" }, { term: "Other Intel (Industry, Competitors, News)", match: "All team members contribute equally" }], correct: 0, explanation: "Account planning is a team sport with defined ownership. The AE and CSM lead the commercial and relationship components — OKRs, growth opportunities, key relationships, pain points, risks. The SE leads the technical component — tech stack. Business impact (ROI) is a joint AE/CSM effort with VC/SE/CSA support. Industry and competitive intel is everyone's responsibility. Knowing who owns what prevents duplicated effort and ensures nothing falls through the cracks.", resource: { label: "Account Planning Best Practices Deck — Account Plan Contributors Table", url: "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit" } },
      { id: 5, type: "mc", lo: "LO2", text: "Momentum is now integrated into Amplitude's sales stack. What is Momentum's primary purpose and how does it connect to account planning?", options: ["Momentum is a forecasting tool that predicts deal close probability based on engagement signals", "Momentum is a conversation intelligence platform that converts call insights into deal updates, delivers meeting summaries and recommended tasks directly into Slack and SFDC, and reduces manual opportunity updates — freeing reps to focus on selling rather than admin", "Momentum is an outbound sequencing tool that automates personalized follow-up emails after discovery calls", "Momentum is a competitive intelligence platform that surfaces competitor mentions from calls and routes them to the PMM team"], correct: 1, explanation: "Momentum is a conversation intelligence platform. It automates deal updates from call transcripts (reducing manual SFDC updates), delivers call summaries, recommended next steps, deal updates, and email drafts directly into Slack DMs and account/team channels. It also writes deal summaries in SFDC. The connection to account planning: Momentum's deal activity feeds into the account's health picture, and Phase 2 plans to support the post-sales handoff and renewal motion — creating a continuous thread across the full customer lifecycle.", resource: { label: "Momentum (for Slack) Deck — Executive Summary", url: "https://docs.google.com/presentation/d/129YPTu9OKQYZM6fFIMxlsJOqalqUWcwlLvLnC4lOvXI/edit" } },
      { id: 6, type: "mc", lo: "LO3", text: "You're building an account plan for a top enterprise prospect. The AI-suggested whitespace shows 3 potential expansion products. Your CSM says they have no relationship with this account yet. What's the right next step?", options: ["Go directly to the economic buyer with the whitespace analysis — they'll appreciate the insight and it signals strategic thinking", "Update the plan with the whitespace opportunities and note 'pending CSM relationship' — review at the next monthly FLM session", "Use the whitespace identification as the catalyst to align the full Pod on account strategy now. Map key stakeholders, identify who has existing relationships, and build a plan to establish contact at multiple levels before you lead with a commercial pitch.", "Deprioritize the whitespace expansion until the account is more established — you can't sell expansion into an account with no CS relationship"], correct: 2, explanation: "Whitespace data from the account plan is only valuable if you have the relationships to act on it. The right move is to use this gap as the trigger for full Pod alignment: Who do we know at this account? Who are the key stakeholders for each whitespace product? What's our first meeting ask? The account plan approach covers Research → Account Goals → Whitespace → Action Plans. Finding whitespace without relationships is a planning gap, not a reason to delay — it's what the account planning process is designed to surface and solve.", resource: { label: "Account Planning Best Practices Deck — Account Planning Approach (Whitespace)", url: "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit" } },
      { id: 7, type: "tf", lo: "LO1", text: "True or False: Momentum includes a bot that joins calls to transcribe them.", options: ["True", "False"], correct: 1, explanation: "Per the Momentum deck: 'Momentum doesn't include a bot to transcribe.' Momentum leverages Zoom transcription (Kaia handles call recording) and its role is in the intelligence and automation layer — converting transcripts into deal updates, summaries, tasks, and email drafts delivered through Slack and SFDC. This distinction matters if a customer asks you how your tools work, and it avoids confusion when setting up the integration for the first time.", resource: { label: "Momentum (for Slack) Deck — Momentum doesn't include a bot to transcribe", url: "https://docs.google.com/presentation/d/129YPTu9OKQYZM6fFIMxlsJOqalqUWcwlLvLnC4lOvXI/edit" } },
      { id: 8, type: "mc", lo: "LO3", text: "Your FLM asks you what a successful account plan looks like in practice. What are the four core components of Amplitude's account planning approach?", options: ["Pipeline, Forecast, Risk, and Action Items", "Research, Account Goals, Whitespace or Challenges, and Action Plans & Tracking", "ICP Fit, Champion Identification, MEDDPICC Validation, and Mutual Action Plan", "Executive Summary, Account Health, Account Intel, and Account Strategy"], correct: 1, explanation: "The four core components of Amplitude's account planning approach are: Research (AI-led), Account Goals — theirs (AI-suggested, Pod-confirmed), Whitespace or Challenges (AI-suggested, Pod-confirmed), and Action Plans & Tracking (Pod-entered). The AI does the heavy lifting on research and suggestions — the Pod's job is to confirm, refine, and own the actions. This design shifts the Pod's effort from busy work to strategy and execution.", resource: { label: "Account Planning Best Practices Deck — Account Planning Approach (4 Core Components)", url: "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "An AE has been at Amplitude for 3 months and is starting their first account plan. They open Salesforce to find the Account Plan tool and get a blank template. Applying Challenger thinking, what should the first meaningful action in the plan document?", options: ["List all open opportunities on the account and their current stage", "Document the account's OKRs and strategic priorities based on their public earnings calls, industry news, job postings, and any discovery conversations — this is the foundation that everything else in the plan builds on", "Map MEDDPICC fields from the current opportunity and use those as the account plan baseline", "Set a revenue target for the account for the next 12 months and work backwards from that number"], correct: 1, explanation: "Account planning starts with understanding the customer's world — not yours. Research into their OKRs, strategic priorities, and business context is the foundation. This is the 'Research → Account Goals (theirs)' phase of the planning approach. Challenger methodology is rooted in the same principle: to Teach effectively, you must understand their business better than they expect you to. A plan that starts with Amplitude's revenue target rather than the customer's goals will produce inside-out pitches, not consultative conversations.", resource: { label: "Account Planning Best Practices Deck — Account Planning Approach (Research → Account Goals)", url: "https://docs.google.com/presentation/d/1E6CvN9brHBGNkS2SZcslVNmaRyaiJhtvw4_Jrq-dJ2c/edit" } },
      { id: 10, type: "fill", lo: "LO1", text: "Momentum delivers call summaries, recommended tasks, deal updates, and email drafts directly into which two systems?", correct: ["Slack and Salesforce", "Slack and SFDC", "SFDC and Slack", "Salesforce and Slack"], placeholder: "two systems...", explanation: "Momentum delivers insights directly into Slack (via DMs and account/team channels) and Salesforce (as deal summaries on opportunity records). This integration means reps don't have to manually update SFDC after every call or hunt for call notes — Momentum surfaces the right information in the tools reps already live in. Phase 1 covers AEs and SDRs. Phase 2 will extend to post-sales roles to support handoffs and renewals.", resource: { label: "Momentum (for Slack) Deck — Momentum Delivers into Slack and SFDC", url: "https://docs.google.com/presentation/d/129YPTu9OKQYZM6fFIMxlsJOqalqUWcwlLvLnC4lOvXI/edit" } },
    ],
  },
  {
    id: "day8", day: "Day 8", title: "Discovery That Accelerates", week: "Week 3",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "The Discovery Question Repository is built to serve multiple GTM roles. Who is it primarily intended for?", options: ["FLMs and enablement managers only — it's a coaching and training resource", "AEs, SDRs, SEs, and other GTM practitioners for use before and during customer conversations", "SEs only — discovery is a technical function that requires product expertise to execute well", "SDRs only — once an AE takes over the opportunity, they should be asking their own questions"], correct: 1, explanation: "The Discovery Question Repository is for AEs, SDRs, SEs, and other GTM practitioners. It's designed as a plug-and-play resource for net new discovery, qualification, POV design, and competitive bake-offs. Enablement and leadership use it for coaching and role-play. The goal: standardize how Amplitude does discovery, tie it to Challenger + MEDDPICC, and accelerate call preparation without starting from scratch every time.", resource: { label: "Discovery Question Repository — Introduction (Who It's For)", url: "https://docs.google.com/document/d/11po0r9LxK_tiooyYb64bdDeqhIhRX_7k-HSlPppf1A4/edit" } },
      { id: 2, type: "mc", lo: "LO2", text: "You're in an S1 Discovery call with a VP of Product at a B2B SaaS company. They say: 'We use a mix of Looker, custom dashboards our engineering team built, and some Google Analytics.' Which discovery question best applies Challenger thinking here?", options: ["'So you have three different tools — which one do you use most?' This clarifies their primary workflow", "'How long does it take for a PM on your team to go from a product question to a decision-ready answer — without needing to open a ticket with engineering or data?' This surfaces the cost of fragmentation.", "'Have you considered a unified platform? Having three tools creates complexity.' This introduces the solution early.", "'Is your engineering team happy managing those custom dashboards?' This checks for internal pain from a technical stakeholder."], correct: 1, explanation: "This is a textbook Challenger discovery move from the Question Repository. A fragmented stack (Looker + custom dashboards + GA) has a real cost — every question that doesn't fit into existing dashboards becomes a ticket. The time-to-answer question surfaces that pain without naming it for them. Let them describe the friction: 'Well, it depends... sometimes a few days.' That's your opening. The other options either accept their frame too quickly or introduce your solution before establishing the problem.", resource: { label: "Discovery Question Repository — S0 Engagement: Context & Current State Questions", url: "https://docs.google.com/document/d/11po0r9LxK_tiooyYb64bdDeqhIhRX_7k-HSlPppf1A4/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "In the CEM, what must be documented in SFDC before an AE can move from S1 to S2?", options: ["Technical use cases validated by the SE and a demo completed", "The 3 Whys (Why Change, Why Now, Why Amplitude), Champion identified, initial MEDDPICC fields populated, and FLM validation of the 3 Whys", "A signed NDA and a formal request for proposal from the customer", "Budget confirmed and decision timeline documented"], correct: 1, explanation: "Per the CEM S1 Discovery exit criteria: Discovery call completed, 3 Whys documented (Why Change, Why Now, Why Amplitude), Champion and/or EB identified, initial MEDDPICC fields completed in SFDC, and FLM validation of the 3 Whys confirmed. Without FLM validation, you cannot advance to S2. This gate exists to ensure deals are real and winnable before significant resources are committed. Documenting it in SFDC isn't admin — it's proof the discovery was thorough.", resource: { label: "Customer Engagement Model — S1 Discovery Exit Criteria (3 Whys + MEDDPICC)", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 4, type: "mc", lo: "LO3", text: "A prospect says: 'We're not in a hurry — we're evaluating a few options over the next 6 months.' Using the Discovery Question Repository's 'Why Now' framework, which question best creates urgency without manufacturing false pressure?", options: ["'If you wait 6 months to decide, our pricing will likely increase.' This is honest about timing constraints.", "'What's driving the 6-month timeline — is there a budget cycle, a product launch, or a specific problem you're trying to solve by then?' This clarifies if the timeline is real or a deflection.", "'OK, let's plan for a follow-up in 5 months then.' This respects their pace without pushing.", "'If nothing changes about your analytics setup over the next 6 months, what breaks first?' This surfaces the cost of delay."], correct: 3, explanation: "The Discovery Question Repository's 'Why Now' category asks: 'If nothing changed in your product analytics approach over the next year, what would break first?' This is a Challenger question — it asks the prospect to articulate the cost of inaction without the AE asserting urgency. It's not a pressure move; it's a Teach move. The prospect either identifies a real risk (which is urgency) or they don't (which tells you they're not qualified yet). Option B is also strong but is more clarifying than urgency-creating. Option D is the best fit for creating owned urgency.", resource: { label: "Discovery Question Repository — S0 Engagement: Priority & Timing ('Why Now?')", url: "https://docs.google.com/document/d/11po0r9LxK_tiooyYb64bdDeqhIhRX_7k-HSlPppf1A4/edit" } },
      { id: 5, type: "tf", lo: "LO1", text: "True or False: The 3 Whys framework used in discovery at Amplitude refers to Why Change, Why Amplitude, and Why This Year.", options: ["True", "False"], correct: 1, explanation: "The 3 Whys per the CEM are: Why Change (what's broken about the status quo), Why Now (what creates urgency — a product launch, board initiative, competitive pressure, fiscal cycle), and Why Amplitude (why us specifically over other options). All three must be documented in SFDC and validated by your FLM at S1. A deal that can't answer all three should not advance to S2 — missing any one of them is a significant qualification risk.", resource: { label: "Customer Engagement Model — S1 Discovery (3 Whys: Why Change, Why Now, Why Amplitude)", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 6, type: "mc", lo: "LO3", text: "An SDR hands off an account to an AE with a brief that says: 'VP Product at a FinServ company, showed interest in analytics after downloading the Northstar Playbook.' The AE opens the S1 call and starts with: 'So, tell me about your current setup.' What's wrong with this approach?", options: ["Nothing — open-ended questions are the foundation of good discovery", "The AE is wasting the first 5 minutes re-establishing context the SDR already captured. The Discovery Question Repository exists so AEs can seed insights from the first question. A better opening: 'In financial services, we often see PMs struggle to connect product behavior data to revenue outcomes — is that a gap you're experiencing?' This is Challenger from question one.", "The AE should have asked for a demo before the discovery call — buyers need to see the product before they'll share information", "The SDR's handoff note is insufficient and the AE should reschedule until they have better context"], correct: 1, explanation: "Starting with 'tell me about your current setup' is the opposite of Challenger discovery. The Discovery Question Repository exists specifically to help AEs show up with a point of view — not a blank slate. At S0, the SDR seeded context. At S1, the AE should open with a commercial insight: something about the VP Product's world in Financial Services that challenges their current assumption. The question 'How long does it take a PM to get a decision-ready answer without needing analyst support?' is a much stronger opener than 'tell me about your setup.'", resource: { label: "Discovery Question Repository — S0 Engagement: Context & Current State (Insight-Led Opening)", url: "https://docs.google.com/document/d/11po0r9LxK_tiooyYb64bdDeqhIhRX_7k-HSlPppf1A4/edit" } },
      { id: 7, type: "match", lo: "LO1", text: "Match each MEDDPICC component to what it is designed to validate in discovery.", pairs: [{ term: "Metrics", match: "What quantifiable outcomes does the customer need to achieve — how will they measure success?" }, { term: "Economic Buyer", match: "Who has final budget authority and can say yes or no regardless of what others want?" }, { term: "Champion", match: "Who has power and influence internally AND wants Amplitude to win — will fight for the deal?" }, { term: "Decision Criteria", match: "What are the formal and informal requirements the customer will use to evaluate and select a solution?" }], correct: 0, explanation: "MEDDPICC is the qualification framework that drives deal hygiene at Amplitude. Each component surfaces a different risk in the deal. Metrics without an Economic Buyer = a deal that will die in procurement. A Champion without Metrics = an enthusiastic user who can't build an internal business case. All MEDDPICC fields must be populated by S2 — and the FLM validates them before the deal advances. The Discovery Question Repository has specific questions mapped to each MEDDPICC component.", resource: { label: "Customer Engagement Model — S1 Discovery MEDDPICC Fields", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "The website https://builtwith.com is recommended in the Discovery Question Repository as a resource for ________ before prospect conversations.", correct: ["research", "account research", "prospect research", "tech stack research", "pre-call research"], placeholder: "what type of preparation...", explanation: "BuiltWith.com is recommended in the Discovery Question Repository as a pre-call research tool. It shows what technologies a prospect is running on their website — analytics tools, tag managers, data tools, CDPs. This intelligence lets you show up to discovery already knowing part of their tech stack, which is a Challenger credibility signal: 'I see you're running [Tool X] — how has that been working for the product team?' It saves time and signals to the prospect that you've done your homework.", resource: { label: "Discovery Question Repository — Resources That Can Help in Discovery (builtwith.com)", url: "https://docs.google.com/document/d/11po0r9LxK_tiooyYb64bdDeqhIhRX_7k-HSlPppf1A4/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "You're in S2 Qualification with a Head of Data Science at a healthcare tech company. They say: 'Our data team handles all analytics requests — we don't have a self-service problem.' A Challenger AE responds: 'How many ad hoc data requests does your team handle per week?' The Head of Data Science says: 'Oh, easily 30-40.' What's the ideal next Challenger move?", options: ["Pivot to a demo — they've surfaced the pain, now show the solution", "Ask: 'What would your team focus on if they weren't fielding those 30-40 requests every week?' This deepens the pain, surfaces the opportunity cost, and lets them articulate the value of self-service in their own words.", "Tell them that Amplitude typically reduces ad hoc requests by 60% — quantify the ROI immediately", "Loop in the SE for a technical deep-dive — this is a data infrastructure conversation the AE shouldn't be leading"], correct: 1, explanation: "This is the Challenger deepening move — they've just revealed the pain, now make them feel it more fully. 'What would your team focus on if they weren't fielding 30-40 requests a week?' forces the Head of Data Science to articulate their own strategic opportunity cost. The answer to that question is your business case. You're not selling Amplitude — you're helping them realize what they're losing. Moving to demo now cuts the discovery short before the pain is fully owned. Quantifying ROI prematurely tells rather than asks — and claims you haven't yet earned.", resource: { label: "Discovery Question Repository — S1 Discovery: Pain & Friction Surfacing", url: "https://docs.google.com/document/d/11po0r9LxK_tiooyYb64bdDeqhIhRX_7k-HSlPppf1A4/edit" } },
      { id: 10, type: "mc", lo: "LO3", text: "Spekit Deal Rooms are available as a discovery resource. What is the primary purpose of a Spekit Deal Room in an active opportunity?", options: ["A Deal Room is a shared workspace where AE and SE co-build the technical evaluation plan", "A Deal Room is a Spekit-hosted microsite where Amplitude can share curated sales content — product overview, case studies, and next-step materials — with a prospect in a personalized, trackable format", "A Deal Room is an internal SFDC view that consolidates all stakeholder contact roles and interaction history for a given opportunity", "A Deal Room is a video call recording library where Amplitude stores all calls with a given prospect for reference during the deal cycle"], correct: 1, explanation: "Spekit Deal Rooms are external-facing, personalized microsites for prospects. They allow Amplitude to share curated content — product overviews, case studies, ROI resources, next-step materials — in a branded, trackable format. The tracking insight is the key value: you can see which content your champion (or their colleagues) engaged with, which signals what they care about and who else is involved in the evaluation. It's a discovery tool as much as a content-sharing tool — champion engagement patterns reveal internal deal dynamics.", resource: { label: "Spekit Deal Rooms Guide (Spekit)", url: "https://app.spekit.co/" } },
    ],
  },
  {
    id: "day9", day: "Day 9", title: "Pricing & Packaging 101", week: "Week 3",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "What are the four platform tiers in Amplitude's 2026 PPL, in order from entry-level to highest?", options: ["Basic, Professional, Business, Enterprise", "Starter, Plus, Growth, Enterprise", "Free, Growth, Enterprise, Custom", "Starter, Growth, Enterprise, Signature"], correct: 1, explanation: "The 2026 PPL has four platform tiers: Starter (free, up to 10K MTU), Plus (up to 50M Events or 500K MTU), Growth (custom events/MTU), and Enterprise (custom events/MTU with the most advanced capabilities). Each tier includes increasing access to platform features, with add-ons available for Growth and Enterprise. Knowing the tiers is foundational — every pricing conversation starts here.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — New Packaging & Pricing (Platform Tiers)", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "The 2026 PPL uses one core pricing metric — either Events or MTUs. Which of the following best describes how they relate?", options: ["MTUs and Events are entirely separate metrics — customers must pick one and cannot convert between them", "1 MTU = 100 Events for cross-metric comparison purposes. Customers choose either Events or MTUs as their contracted metric and are priced on that basis. The platform price is the same across both.", "MTUs are only available for Enterprise tier — Growth customers must use Events", "Events are the preferred metric and MTUs are being phased out with 2026 PPL"], correct: 1, explanation: "The 2026 PPL simplified pricing down to ONE core metric — Events OR MTUs. The conversion rate is 1 MTU = 100 Events, used for cross-metric comparison only. Quotes must use the customer's contracted metric. The platform price is the same whether pricing by EV or MTU. This simplification replaced the complex multi-metric approach of legacy plans.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — One Core Meter: EV or MTU (1 MTU = 100 Events)", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "A prospect asks: 'How much does Session Replay cost?' You know they're interested in Growth Analytics. What's the most accurate answer?", options: ["Session Replay is included at no additional cost with Growth Analytics", "Session Replay is priced as a standalone SKU based on number of sessions recorded", "Session Replay is a separate add-on priced at 15% of the SW Pillar (Analytics) net total. A standard SR add-on includes sessions up to 5M/month for Growth and 10M/month for Enterprise under fair use limits — with a custom SR SKU available for higher volumes at additional cost.", "Session Replay pricing varies by use case and requires a Deal Desk quote before any number can be shared with a prospect"], correct: 2, explanation: "Session Replay is a POT (Percent-of-Total) add-on priced at 15% of the SW Pillar net total. The standard SR SKU includes up to 5M sessions/month for Growth and 10M for Enterprise (fair use limits covering 95%+ of use cases). Standard SR retention is 3 months (90 days) — longer retention requires additional cost. Customers needing more than the fair use limits can get a Custom SR SKU priced by session count. For pricing help, open a Deal Desk case in SFDC.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Session Replay SKUs (Standard vs Custom)", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 4, type: "mc", lo: "LO3", text: "An AE quotes a Growth Analytics deal and includes Session Replay and Feature Experimentation as add-ons. The prospect's VP of Finance asks: 'Can you explain why the add-ons cost what they do?' What's the right framing?", options: ["Add-on pricing is fixed regardless of analytics spend — it's a flat annual fee per product", "Add-on pricing is a percentage uplift on the Analytics platform net total, which means the more analytics volume you buy, the more value you get per dollar on add-ons — they scale with your usage.", "Add-on pricing is negotiated separately and is unrelated to the platform price", "Add-on pricing is based on the number of users who access each product — more seats means more cost"], correct: 1, explanation: "2026 PPL add-ons are priced as a percentage of the SW Pillar net total (POT pricing). Session Replay = 15%, Feature Experimentation = 50%, Web Experimentation = 30%, Activation = 30%, Guides & Surveys = 30%. This means add-on cost scales with analytics investment — customers who buy more analytics get more product for proportionally the same price. The goal: simplify pricing and incentivize platform-wide adoption. This framing also reinforces the platform consolidation story over buying point solutions.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Add-Ons Priced as % Uplift on Platform", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 5, type: "match", lo: "LO1", text: "Match each add-on product to its POT percentage of the SW Pillar net total.", pairs: [{ term: "Session Replay", match: "15% of SW Pillar net total" }, { term: "Feature Experimentation", match: "50% of SW Pillar net total" }, { term: "Web Experimentation", match: "30% of SW Pillar net total" }, { term: "Guides & Surveys", match: "30% of SW Pillar net total" }], correct: 0, explanation: "POT percentages are the key pricing facts for add-on conversations. Feature Experimentation at 50% reflects its strategic value and depth. Session Replay and AI Feedback at 15% are positioned as accessible entry points that deepen platform stickiness. Guides & Surveys, Web Experimentation, and Activation at 30% reflect their high usage footprint. Knowing these rates helps you scope deals quickly and position add-ons confidently without needing to open a Deal Desk case for every estimate.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Add-On Pricing (POT Percentages)", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 6, type: "tf", lo: "LO1", text: "True or False: The 2026 PPL has a platform fee (minimum spend floor) in addition to volume-based pricing.", options: ["True", "False"], correct: 1, explanation: "One of the key simplifications in 2026 PPL is the removal of the platform fee. Previous plans had minimum fees that made low-volume deals appear expensive relative to what customers were getting. The new model: one unit rate per tier, no floor, no platform minimum. This makes pricing more transparent and easier to explain to buyers — and reduces churn risk from customers who feel they're paying for capacity they're not using.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — No Platform Fee or Minimum Block Pricing", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 7, type: "mc", lo: "LO2", text: "A prospect asks about a 3-year deal. Your standard term is 3 years — what is the pricing implication for shorter terms?", options: ["Shorter terms get discounts — 1-year deals are cheaper than 3-year deals", "All term lengths are priced the same — Amplitude doesn't discount based on commitment length", "Standard term is 3 years. For each year reduced, price is uplifted by 5-10%. A 1-year deal costs 10-20% more than the same 3-year commitment.", "Shorter terms require Deal Desk approval but carry no pricing premium"], correct: 2, explanation: "Per the 2026 PPL: standard term is 3 years. For each year reduced from the standard, uplift price by 5-10%. This creates a meaningful incentive for multi-year commitments — a 1-year deal is priced 10-20% higher than the equivalent 3-year deal. This is part of 'weaponizing pricing' to create commercially attractive structures that benefit both Amplitude and the customer. Use this to position multi-year deals: 'If we can structure this as a 3-year, here's what that does for your unit price.'", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Weaponizing Pricing: Standard Term & Uplift", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "For general questions about 2026 PPL packaging and pricing, the correct Slack channel to post in is ________.", correct: ["#gtm-pricing-packaging-help", "gtm-pricing-packaging-help", "#gtm-pricing-packaging", "gtm-pricing-packaging"], placeholder: "Slack channel name...", explanation: "#gtm-pricing-packaging-help is the designated Slack channel for all 2026 PPL pricing and packaging questions. For pricing and quoting help on a specific deal, open a SFDC case with Deal Desk from the opportunity. Knowing the right channel saves time and gets you to the right expert: Sales Finance for deal structuring, Deal Desk for quoting, #gtm-pricing-packaging-help for general PPL questions.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — How to Get Help (#gtm-pricing-packaging-help)", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "You're proposing a 3-year Enterprise deal. Per 2026 PPL, implementation services are mandatory at land. The deal is $250K ARR. What's the required implementation SKU, and what's the maximum discount you can apply before a PS carve kicks in?", options: ["No implementation required — services are optional on all deals", "Core Platform Implementation is required; you can discount up to 50% before a carve", "The mandatory implementation SKU is determined by ARR tier. At $250K the Essential Platform tier applies. The maximum discount before PS carve is 25%.", "Custom SOW is required for all deals over $100K; no discount is permitted without CRO approval"], correct: 2, explanation: "Implementation services are mandatory on all 2026 PPL Growth/Enterprise land deals, with the required SKU determined by ARR tier. The 25% maximum discount before PS carve applies across tiers — beyond that, the carve reduces your ARR credit. Custom SOW (and separate approval) applies only for deals over $500K ARR. If you need to waive the implementation requirement (e.g., partner-delivered services), you need Deal Desk + CRO approval. Understanding the PS mandate prevents deal delays at the finish line.", resource: { label: "Deal Desk + CPQ Slides — PS Mandatory Attach & ARR Tier Implementation SKUs", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 10, type: "mc", lo: "LO3", text: "A customer on a Growth Analytics plan is consistently running at 110% of their contracted event volume. How should you handle this, and what is Amplitude's approach to overages?", options: ["Invoice them immediately for the overage — they've breached their contract", "Ignore it until renewal — overages are only addressed at the renewal conversation", "Amplitude takes a customer-first, non-punitive approach to overages. Work with the customer to right-size their contracted volume via a timely upsell. If you can complete a co-term volume upsell, Amplitude will waive overages incurred. The Finance team provides monthly overage reporting to help field teams identify and engage customers proactively.", "Notify the Finance team and let them manage the overage conversation — AEs aren't responsible for usage compliance"], correct: 2, explanation: "Amplitude's overage policy is explicitly customer-first and non-punitive. The preferred approach is to work with the customer to co-term a volume upsell — a timely upsell waives overages. AEs have access to overage email templates to position the upsell conversation constructively. GTM teams can recommend customers for overage escalation to Finance (billing@amplitude.com) only if the customer is unresponsive after good-faith outreach. Monthly overage reports from Finance give you the data to manage this proactively, not reactively.", resource: { label: "2026 Sales Finance & PPL Enablement Deck — Consumption & Account Health / Overage Policy", url: "https://docs.google.com/presentation/d/1DSdaoKmUJEhADvjIC6-ceKKMoHd8N1x9-zF17wtzv3Q/edit" } },
    ],
  },
  {
    id: "day10", day: "Day 10", title: "PSP & Implementation Pitch", week: "Week 3",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "The PSP & Implementation Pitch describes Amplitude's partnership approach as having a target time to value. What is that target?", options: ["30 days from contract signing", "Less than 60 days from contract signing", "90 days from contract signing", "120 days from contract signing"], correct: 1, explanation: "Per the PSP & Implementation Pitch: Amplitude's partnership approach targets time to value of less than 60 days. This is a key differentiator — many enterprise analytics implementations take 6+ months. The ability to say 'you'll be live and getting value in under 60 days' directly addresses buyer risk aversion and shortens the time between spend and impact.", resource: { label: "PSP & Implementation Pitch Slides — Partnership Approach: Time to Value <60 Days", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "Amplitude's implementation and onboarding process is structured in three phases. What are they?", options: ["Planning, Execution, and Go-Live", "Discovery, Development, and Testing", "Kickoff & Foundation, Build & Validate, and Launch & Optimize", "Assessment, Implementation, and Support"], correct: 2, explanation: "Per the PSP & Implementation Pitch, the three onboarding phases are: Kickoff & Foundation, Build & Validate, and Launch & Optimize. This phased approach ensures a structured path from contract signing to production usage — each phase has clear milestones and deliverables. Knowing these phases helps you set expectations with customers during the sale and align with the PS team on what's included.", resource: { label: "PSP & Implementation Pitch Slides — Implementation & Onboarding: 3 Phases", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
      { id: 3, type: "mc", lo: "LO1", text: "Under the 2026 PPL, implementation services are mandatory for Growth and Enterprise land deals. Where is this policy documented?", options: ["The CEM Renewal Motion document", "The Deal Desk + CPQ slides — mandatory implementation attach for 2026 PPL lands", "The Sales Policy Handbook only", "It's communicated verbally by Deal Desk on a per-deal basis"], correct: 1, explanation: "The mandatory implementation attach for 2026 PPL Growth and Enterprise land deals is documented in the Deal Desk + CPQ slides. This policy ensures every new customer gets a structured onboarding experience — which directly impacts time to value, adoption, and ultimately renewal. Understanding this mandate prevents deal delays: if you build a quote without implementation, CPQ will block it.", resource: { label: "Deal Desk + CPQ Slides — Mandatory Implementation Attach for 2026 PPL Lands", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 4, type: "match", lo: "LO1", text: "Match each Premium Success Package (PSP) tier to its key differentiator.", pairs: [{ term: "PSP Essential", match: "Core implementation support — structured onboarding, data validation, and initial use case configuration" }, { term: "PSP Advanced", match: "Deeper engagement — includes everything in Essential plus advanced use case development, custom training, and extended support" }, { term: "PSP Premium", match: "Highest tier — includes a dedicated Technical Success Manager (TSM), strategic advisory, and ongoing optimization beyond initial implementation" }, { term: "Consultative Implementation", match: "NOT included in any PSP tier — this is a separate PS engagement for customers needing deep, custom consulting work" }], correct: 0, explanation: "PSP tiers provide escalating levels of post-sale support. Essential covers the basics of getting live. Advanced adds deeper use case work and custom training. Premium provides a dedicated TSM for ongoing strategic partnership. Critically, Consultative Implementation is NOT part of any PSP — it's a separate engagement. Knowing this distinction prevents over-promising during the sale and ensures you're positioning the right level of services for each customer's needs.", resource: { label: "PSP & Implementation Pitch Slides — Premium Success Packages (PSP Tiers)", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
      { id: 5, type: "mc", lo: "LO2", text: "A prospect's VP of Engineering asks: 'What kind of commitment do we need from our side during implementation?' How do you answer?", options: ["Minimal — Amplitude handles all implementation work and your team just needs to approve the final setup", "Typically ~0.3 FTE each from a Product Manager, Data Engineer/Architect, and Engineering Manager — Amplitude provides the implementation team, but customer roles are essential for data validation, use case alignment, and organizational adoption", "Full-time dedicated project manager from the customer side for the entire implementation period", "Just one technical contact who can respond to questions within 24 hours"], correct: 1, explanation: "Per the PSP & Implementation Pitch: customer roles during implementation require approximately 0.3 FTE each — typically a Product Manager (owns use cases and success criteria), a Data Engineer/Architect (owns data structure and validation), and an Engineering Manager (owns SDK implementation and technical resources). This is a partnership model, not a turnkey service. Setting this expectation during the sale prevents implementation delays caused by under-resourced customer teams.", resource: { label: "PSP & Implementation Pitch Slides — Implementation Resources: Customer Roles (~0.3 FTE each)", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
      { id: 6, type: "mc", lo: "LO2", text: "A customer asks: 'What exactly is included in the PSP we're buying?' You need to give a clear answer. What's included in a standard PSP?", options: ["Unlimited consulting hours with an Amplitude analytics expert for the contract term", "Structured implementation support, data validation, use case configuration, training, and ongoing success management — scoped by PSP tier (Essential, Advanced, or Premium). Each tier has defined deliverables and time allocations.", "A dedicated Amplitude employee embedded in the customer's office for the first 90 days", "Access to Amplitude University courses and a quarterly business review"], correct: 1, explanation: "PSPs are structured service packages with defined deliverables per tier. They include implementation support (onboarding phases), data validation, use case configuration, training sessions, and success management. The scope scales with the tier — Essential, Advanced, and Premium each have increasing depth. What's NOT included: consultative implementation (deep custom consulting) and ongoing ad hoc analytics work. Being precise about what's in and out of scope prevents post-sale disappointment.", resource: { label: "PSP & Implementation Pitch Slides — Premium Success Packages: What's Included", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
      { id: 7, type: "tf", lo: "LO1", text: "True or False: PSP (Premium Success Packages) includes consultative implementation services — deep, custom consulting engagements where Amplitude acts as an embedded analytics advisor.", options: ["True", "False"], correct: 1, explanation: "PSP does NOT include consultative implementation. This is explicitly called out in the PSP & Implementation Pitch. PSP covers structured onboarding, implementation support, and success management. Consultative implementation — where Amplitude provides deep, custom consulting as an embedded analytics advisor — is a separate PS engagement with its own scoping and pricing. Mixing these up during the sale creates scope expectations that PSP can't deliver on.", resource: { label: "PSP & Implementation Pitch Slides — PSP Does NOT Include Consultative Implementation", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
      { id: 8, type: "mc", lo: "LO2", text: "During a deal, the prospect asks who from Amplitude will be responsible for their implementation. What's the correct answer about Amplitude's implementation team structure?", options: ["A single Implementation Consultant handles everything from kickoff to go-live", "The implementation is fully automated — customers self-serve through Amplitude's onboarding wizard", "Amplitude assigns an implementation team led by the customer's Sub-co (implementation lead) with TSM accountability. The TSM provides strategic oversight while the Sub-co manages day-to-day execution.", "The AE stays involved as the primary implementation contact until the first QBR"], correct: 2, explanation: "Per the PSP & Implementation Pitch: the customer's Amplitude implementation team includes a Sub-co (implementation lead who manages day-to-day execution) and a TSM (Technical Success Manager who provides strategic accountability and oversight). This structure ensures both tactical execution and strategic alignment. The AE completes the handoff per the CEM S6.5 process — they don't stay as the implementation contact.", resource: { label: "PSP & Implementation Pitch Slides — Your Implementation Team (Sub-co / TSM Accountability)", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
      { id: 9, type: "mc", lo: "LO1", text: "When a partner prospect MQL comes in through the TOFU process, who does it route to?", options: ["The AE who owns the territory", "The SDR team for initial qualification before AE handoff", "The Partner Sales Manager (PSM) — partner prospect MQLs route to PSMs, not AEs or SDRs", "The Partner Solutions Architect for technical qualification"], correct: 2, explanation: "Per the TOFU Training Deck: MQL routing for partner prospects goes to the Partner Sales Manager (PSM), not to AEs or SDRs. This routing ensures that partner-sourced opportunities are handled by the team with the partner relationship context and co-sell expertise. Understanding this routing prevents confusion when you see a partner MQL in your territory — it's not yours to work, it's the PSM's.", resource: { label: "TOFU Training Deck — MQL Routing: Partner Prospect Routes to PSM", url: "https://docs.google.com/presentation/d/1cFxBuOQyJxSEnN34JrolHsnzc2DhdgUX-bxtBM_xYDM/edit" } },
      { id: 10, type: "mc", lo: "LO3", text: "You've closed a deal with PSP Advanced attached. Per the CEM, what does the AE's post-sale responsibility include regarding the ongoing customer partnership?", options: ["Nothing — once the deal is closed, the TSM and CSM own the relationship entirely", "The AE creates a Mutual Success Plan (MSP) with the customer and TSM that outlines the ongoing partnership: quarterly business reviews, adoption milestones, expansion triggers, and renewal timeline. The MSP ensures continuity between the sale and the post-sale experience.", "The AE schedules a 30-day check-in call and then transitions fully to CS", "The AE monitors product usage dashboards monthly and flags any decline to the CSM"], correct: 1, explanation: "Per the PSP & Implementation Pitch: the Mutual Success Plan (MSP) is the bridge between sale and ongoing partnership. It documents: business objectives, adoption milestones, QBR cadence, expansion triggers, and renewal timeline. The AE is responsible for initiating this at the post-sale handoff — ensuring the customer's expectations from the sale are captured and carried forward by the TSM/CSM team. A deal without an MSP is a deal where promises made during the sale can get lost in the handoff.", resource: { label: "PSP & Implementation Pitch Slides — Mutual Success Plan (Ongoing Partnership)", url: "https://docs.google.com/presentation/d/1JJlncSiWqwnxVLbTuuZrpHIgeje0RkGQobWFqlrM_f4/edit" } },
    ],
  },
];
